import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { ReservationStatus, Reservation, RoomStatus, PaymentStatus, Room, Client } from '../types';
import { Search, Plus, Filter, LogIn, LogOut, Trash2, AlertTriangle, UserPlus, ChevronLeft, ChevronRight } from 'lucide-react';

const MiniCalendar = ({ selectedDate, onChange, label }: { selectedDate: string, onChange: (date: string) => void, label: string }) => {
    const [viewDate, setViewDate] = useState(selectedDate ? new Date(selectedDate) : new Date());
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    useEffect(() => {
        if (selectedDate) {
            const [y, m, d] = selectedDate.split('-').map(Number);
            setViewDate(new Date(y, m - 1, d));
        }
    }, [selectedDate]);

    const getDaysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
    const getFirstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

    const year = viewDate.getFullYear();
    const month = viewDate.getMonth();
    const daysInMonth = getDaysInMonth(year, month);
    const startDay = getFirstDayOfMonth(year, month);

    const handlePrevMonth = (e: React.MouseEvent) => { e.preventDefault(); setViewDate(new Date(year, month - 1, 1)); };
    const handleNextMonth = (e: React.MouseEvent) => { e.preventDefault(); setViewDate(new Date(year, month + 1, 1)); };

    const handleDayClick = (day: number, isPast: boolean) => {
        if (isPast) return;
        const m = (month + 1).toString().padStart(2, '0');
        const d = day.toString().padStart(2, '0');
        onChange(`${year}-${m}-${d}`);
    };

    const monthNames = ["Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"];

    return (
        <div className="border border-slate-200 rounded-lg p-3 bg-white w-full">
            <label className="block text-sm font-medium text-slate-700 mb-2">{label}</label>
            <div className="flex justify-between items-center mb-2 bg-slate-50 p-1 rounded">
                <button onClick={handlePrevMonth} className="p-1 hover:bg-slate-200 rounded text-slate-600"><ChevronLeft size={16} /></button>
                <span className="font-semibold text-sm text-slate-800">{monthNames[month]} {year}</span>
                <button onClick={handleNextMonth} className="p-1 hover:bg-slate-200 rounded text-slate-600"><ChevronRight size={16} /></button>
            </div>
            <div className="grid grid-cols-7 gap-1 text-center">
                {['D','L','M','M','J','V','S'].map((d, i) => (<div key={i} className="text-[10px] text-slate-400 font-bold">{d}</div>))}
                {Array.from({ length: startDay }).map((_, i) => (<div key={`empty-${i}`} />))}
                {Array.from({ length: daysInMonth }).map((_, i) => {
                    const day = i + 1;
                    const dateToCheck = new Date(year, month, day);
                    const isPast = dateToCheck < today;
                    const dateStr = `${year}-${(month + 1).toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
                    const isSelected = selectedDate === dateStr;
                    return (
                        <button key={day} type="button" onClick={() => handleDayClick(day, isPast)} disabled={isPast}
                            className={`h-7 w-7 text-xs rounded-full flex items-center justify-center transition-all ${isSelected ? 'bg-indigo-600 text-white font-bold' : isPast ? 'text-slate-300 cursor-not-allowed' : 'text-slate-700 hover:bg-indigo-50'}`}
                        >{day}</button>
                    )
                })}
            </div>
        </div>
    );
};

const Bookings: React.FC = () => {
  const { reservations, rooms, clients, updateReservationStatus, addReservation, addClient, deleteReservation } = useApp();
  const [filter, setFilter] = useState('all');
  const [showModal, setShowModal] = useState(false);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [reservationToDelete, setReservationToDelete] = useState<string | null>(null);

  const [dates, setDates] = useState({ checkIn: '', checkOut: '' });
  const [availableRooms, setAvailableRooms] = useState<Room[]>([]);
  const [selectedRoomId, setSelectedRoomId] = useState('');
  const [selectedClientId, setSelectedClientId] = useState('');
  const [deposit, setDeposit] = useState(0);
  const [discount, setDiscount] = useState(0);

  const [isAddingClient, setIsAddingClient] = useState(false);
  const [newClient, setNewClient] = useState<Partial<Client>>({ firstName: '', lastName: '', phone: '', documentNumber: '' });

  useEffect(() => {
    if (dates.checkIn && dates.checkOut) {
        const start = new Date(dates.checkIn + 'T00:00:00');
        const end = new Date(dates.checkOut + 'T00:00:00');
        const available = rooms.filter(room => {
            return !reservations.some(res => {
                if (res.roomId !== room.id || res.status === ReservationStatus.CANCELLED) return false;
                const resStart = new Date(res.checkIn + 'T00:00:00');
                const resEnd = new Date(res.checkOut + 'T00:00:00');
                return start < resEnd && end > resStart;
            });
        });
        setAvailableRooms(available);
    }
  }, [dates, reservations, rooms]);

  const handleCreateReservation = () => {
     const room = rooms.find(r => r.id === selectedRoomId);
     if(!room || !selectedClientId) return alert("Complete los datos");

     const diffDays = Math.ceil(Math.abs(new Date(dates.checkOut).getTime() - new Date(dates.checkIn).getTime()) / (1000 * 60 * 60 * 24)); 
     const subtotal = diffDays * room.pricePerNight;
     const finalTotal = subtotal * (1 - (discount / 100));

     addReservation({
         id: `R-${Date.now().toString().slice(-4)}`,
         clientId: selectedClientId,
         roomId: selectedRoomId,
         checkIn: dates.checkIn,
         checkOut: dates.checkOut,
         status: ReservationStatus.CONFIRMED,
         totalAmount: finalTotal,
         deposit: deposit,
         discount: discount,
         paymentStatus: PaymentStatus.PENDING,
         storeCharges: 0
     });
     setShowModal(false);
     setDates({ checkIn: '', checkOut: '' });
     setDiscount(0);
     setDeposit(0);
  };

  const filteredReservations = filter === 'all' ? reservations : reservations.filter(r => r.status === filter);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h2 className="text-3xl font-bold text-slate-800">Reservas</h2>
        <button onClick={() => setShowModal(true)} className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center hover:bg-indigo-700 transition w-full sm:w-auto justify-center">
          <Plus size={18} className="mr-2" /> Nueva Reserva
        </button>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col sm:flex-row gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
          <input type="text" placeholder="Buscar..." className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg" />
        </div>
        <select className="border border-slate-200 rounded-lg py-2 px-3 focus:outline-none" value={filter} onChange={(e) => setFilter(e.target.value)}>
            <option value="all">Todos los estados</option>
            <option value={ReservationStatus.CONFIRMED}>Confirmadas</option>
            <option value={ReservationStatus.CHECKED_IN}>Check-In</option>
        </select>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 text-slate-600 text-sm uppercase tracking-wider">
                <th className="p-4 font-semibold">ID</th>
                <th className="p-4 font-semibold">Cliente</th>
                <th className="p-4 font-semibold">Depto</th>
                <th className="p-4 font-semibold">Check-In</th>
                <th className="p-4 font-semibold">Check-Out</th>
                <th className="p-4 font-semibold">Total</th>
                <th className="p-4 font-semibold text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredReservations.map((res) => {
                  const client = clients.find(c => c.id === res.clientId);
                  const room = rooms.find(r => r.id === res.roomId);
                  return (
                    <tr key={res.id} className="hover:bg-slate-50 text-sm">
                        <td className="p-4 font-medium">#{res.id}</td>
                        <td className="p-4">{client?.firstName} {client?.lastName}</td>
                        <td className="p-4">{room?.number}</td>
                        <td className="p-4">{res.checkIn}</td>
                        <td className="p-4">{res.checkOut}</td>
                        <td className="p-4 font-bold text-indigo-700">
                            ${res.totalAmount.toLocaleString()}
                            {res.discount ? <span className="block text-[10px] text-green-600">Desc. {res.discount}%</span> : null}
                        </td>
                        <td className="p-4 text-right flex justify-end gap-2">
                            {res.status === ReservationStatus.CONFIRMED && (
                                <button onClick={() => updateReservationStatus(res.id, ReservationStatus.CHECKED_IN)} className="p-2 bg-emerald-50 text-emerald-600 rounded hover:bg-emerald-100"><LogIn size={18} /></button>
                            )}
                            <button onClick={() => { setReservationToDelete(res.id); setShowDeleteModal(true); }} className="p-2 bg-red-50 text-red-600 rounded hover:bg-red-100"><Trash2 size={18} /></button>
                        </td>
                    </tr>
                  );
              })}
            </tbody>
          </table>
          {filteredReservations.length === 0 && <div className="p-8 text-center text-slate-500">No hay reservas registradas.</div>}
        </div>
      </div>

      {showModal && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[100] p-4">
              <div className="bg-white rounded-xl w-full max-w-2xl max-h-[90vh] overflow-y-auto shadow-2xl">
                  <div className="p-6 border-b border-slate-100 flex justify-between items-center">
                      <h3 className="text-xl font-bold text-slate-800">Nueva Reserva</h3>
                      <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600"><X size={24}/></button>
                  </div>
                  <div className="p-6 space-y-6">
                       <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                           <MiniCalendar label="Fecha Check-In" selectedDate={dates.checkIn} onChange={(d) => setDates(prev => ({ ...prev, checkIn: d }))} />
                           <MiniCalendar label="Fecha Check-Out" selectedDate={dates.checkOut} onChange={(d) => setDates(prev => ({ ...prev, checkOut: d }))} />
                       </div>
                       <div>
                          <label className="block text-sm font-medium text-slate-700 mb-2">Departamento Disponible</label>
                          <select className="w-full border rounded-lg p-3" value={selectedRoomId} onChange={(e) => setSelectedRoomId(e.target.value)}>
                                <option value="">-- Seleccione un depto --</option>
                                {availableRooms.map(room => (<option key={room.id} value={room.id}>{room.number} - ${room.pricePerNight}/noche</option>))}
                          </select>
                       </div>
                       <div>
                           <label className="block text-sm font-medium text-slate-700 mb-2">Cliente</label>
                           <select className="w-full border rounded-lg p-3" value={selectedClientId} onChange={e => setSelectedClientId(e.target.value)}>
                                <option value="">-- Seleccionar Cliente --</option>
                                {clients.map(c => <option key={c.id} value={c.id}>{c.firstName} {c.lastName}</option>)}
                           </select>
                       </div>
                       <div className="grid grid-cols-2 gap-4">
                           <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Seña ($)</label>
                                <input type="number" className="w-full border rounded-lg p-2" value={deposit} onChange={e => setDeposit(Number(e.target.value))} />
                           </div>
                           <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Descuento (%)</label>
                                <input type="number" className="w-full border rounded-lg p-2" value={discount} onChange={e => setDiscount(Number(e.target.value))} />
                           </div>
                       </div>
                  </div>
                  <div className="p-6 border-t border-slate-100 bg-slate-50 flex justify-end gap-3">
                      <button onClick={() => setShowModal(false)} className="px-4 py-2 text-slate-600">Cancelar</button>
                      <button onClick={handleCreateReservation} className="px-6 py-2 bg-indigo-600 text-white rounded-lg">Confirmar Reserva</button>
                  </div>
              </div>
          </div>
      )}

      {showDeleteModal && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-[110] p-4 backdrop-blur-sm">
            <div className="bg-white p-6 rounded-xl w-full max-w-sm shadow-2xl text-center">
                <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600"><AlertTriangle size={32} /></div>
                <h3 className="text-xl font-bold text-slate-800 mb-2">¿Eliminar Reserva?</h3>
                <p className="text-slate-500 mb-6 text-sm">Esta acción borrará la reserva definitivamente y liberará la habitación.</p>
                <div className="flex gap-3 justify-center">
                    <button onClick={() => setShowDeleteModal(false)} className="flex-1 py-2.5 bg-slate-100 rounded-lg">Cancelar</button>
                    <button onClick={() => { deleteReservation(reservationToDelete!); setShowDeleteModal(false); }} className="flex-1 py-2.5 bg-red-600 text-white rounded-lg font-semibold">Sí, Eliminar</button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

