  const [availableRooms, setAvailableRooms] = useState<Room[]>([]);
  const [selectedRoomId, setSelectedRoomId] = useState('');
  const [selectedClientId, setSelectedClientId] = useState('');
  const [deposit, setDeposit] = useState(0);
  const [occupancyType, setOccupancyType] = useState<'full' | '2pax'>('full');

  useEffect(() => {
    if (dates.checkIn && dates.checkOut) {
        const start = new Date(dates.checkIn + 'T00:00:00');
        const end = new Date(dates.checkOut + 'T00:00:00');
        const available = rooms.filter(room => {
            return !reservations.some(res => {
                if (editingResId && res.id === editingResId) return false;
                if (res.roomId !== room.id || res.status === ReservationStatus.CANCELLED) return false;

                const resStart = new Date(res.checkIn + 'T00:00:00');
                const resEnd = new Date(res.checkOut + 'T00:00:00');
                return start < resEnd && end > resStart;
            });
        });
        setAvailableRooms(available);
    }
  }, [dates, reservations, rooms, editingResId]);

  const resetForm = () => {
    setDates({ checkIn: '', checkOut: '' });
    setSelectedRoomId('');
    setSelectedClientId('');
    setDeposit(0);
    setEditingResId(null);
    setIsAddingClient(false);
    setOccupancyType('full');
  };

  const handleOpenEdit = (res: Reservation) => {
    setEditingResId(res.id);
    setDates({ checkIn: res.checkIn, checkOut: res.checkOut });
    setSelectedRoomId(res.roomId);
    setSelectedClientId(res.clientId);
    setDeposit(res.deposit || 0);
    setOccupancyType(res.occupancyType || 'full');
    setShowModal(true);
  };

  const handleRequestDelete = (id: string) => {
    setResToDeleteId(id);
    setShowDeleteModal(true);
  };

  const handleConfirmDelete = () => {
    if (resToDeleteId) {
        deleteReservation(resToDeleteId);
        setShowDeleteModal(false);
        setResToDeleteId(null);
    }
  };

  const handleSaveReservation = () => {
     const room = rooms.find(r => r.id === selectedRoomId);
     if(!room || !selectedClientId) return alert("Por favor, seleccione un departamento y un cliente.");

     const diffDays = Math.ceil(Math.abs(new Date(dates.checkOut).getTime() - new Date(dates.checkIn).getTime()) / (1000 * 60 * 60 * 24)); 

     // Usamos la tarifa según la ocupación seleccionada
     const pricePerNight = occupancyType === '2pax' ? (room.pricePerNight2Pax || room.pricePerNight) : room.pricePerNight;
     const total = diffDays * pricePerNight;

     const reservationData: Reservation = {
         id: editingResId || `R-${Date.now().toString().slice(-4)}`,
         clientId: selectedClientId,
         roomId: selectedRoomId,
         checkIn: dates.checkIn,
         checkOut: dates.checkOut,
         status: editingResId ? (reservations.find(r => r.id === editingResId)?.status || ReservationStatus.CONFIRMED) : ReservationStatus.CONFIRMED,
         totalAmount: total,
         deposit: deposit,
         paymentStatus: PaymentStatus.PENDING,
         storeCharges: editingResId ? (reservations.find(r => r.id === editingResId)?.storeCharges || 0) : 0,
         occupancyType: occupancyType
     };

     if (editingResId) {
        updateReservation(reservationData);
     } else {
        addReservation(reservationData);
     }

     setShowModal(false);
     resetForm();
  };

  const handleQuickAddClient = () => {
      if (!newClientData.firstName || !newClientData.lastName || !newClientData.documentNumber) {
          alert("Por favor complete los datos obligatorios del cliente (Nombre, Apellido y DNI)");
          return;
      }
      const newId = `c-${Date.now()}`;
      addClient({
          ...newClientData,
          id: newId
      } as Client);

      setSelectedClientId(newId);
      setIsAddingClient(false);
      setNewClientData({ firstName: '', lastName: '', documentNumber: '', phone: '' });
  };

  const [isAddingClient, setIsAddingClient] = useState(false);
  const [newClientData, setNewClientData] = useState<Partial<Client>>({
      firstName: '',
      lastName: '',
      documentNumber: '',
      phone: ''
  });

  const filteredReservations = filter === 'all' ? reservations : reservations.filter(r => r.status === filter);

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-3xl font-bold text-slate-900">Reservas</h2>
        <button onClick={() => { resetForm(); setShowModal(true); }} className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl flex items-center hover:bg-indigo-700 transition shadow-lg shadow-indigo-100 font-bold">
          <Plus size={18} className="mr-2" /> Nueva Reserva
        </button>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-500" size={18} />
          <input 
            type="text" 
            placeholder="Buscar por cliente o ID..." 
            className="w-full pl-10 pr-4 py-2.5 border border-slate-300 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-slate-900 font-medium transition-all" 
          />
        </div>
        <select 
            className="border border-slate-300 rounded-xl py-2 px-4 outline-none focus:ring-2 focus:ring-indigo-500 text-slate-900 font-bold bg-white" 
            value={filter} 
            onChange={(e) => setFilter(e.target.value)}
        >
            <option value="all">Todos los estados</option>
            <option value={ReservationStatus.CONFIRMED}>Confirmadas</option>
            <option value={ReservationStatus.CHECKED_IN}>Check-In</option>
        </select>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-100 text-slate-700 text-xs uppercase tracking-widest">
                <th className="p-4 font-black">ID</th>
                <th className="p-4 font-black">Cliente</th>
                <th className="p-4 font-black">Depto</th>
                <th className="p-4 font-black text-center">Ocup.</th>
                <th className="p-4 font-black">Check-In</th>
                <th className="p-4 font-black">Check-Out</th>
                <th className="p-4 font-black text-right">Monto</th>
                <th className="p-4 font-black text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredReservations.map((res) => {
                  const client = clients.find(c => c.id === res.clientId);
                  const room = rooms.find(r => r.id === res.roomId);
                  return (
                    <tr key={res.id} className="hover:bg-indigo-50/30 transition text-sm">
                        <td className="p-4 font-bold text-slate-900">#{res.id}</td>
                        <td className="p-4 text-slate-800 font-medium">{client?.firstName} {client?.lastName}</td>
                        <td className="p-4 font-bold text-slate-900">{room?.number}</td>
                        <td className="p-4 text-center">
                            {res.occupancyType === '2pax' ? (
                                <span className="text-[10px] bg-amber-100 text-amber-700 px-2 py-0.5 rounded font-black uppercase">2 Pax</span>
                            ) : (
                                <span className="text-[10px] bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded font-black uppercase">Full</span>
                            )}
                        </td>
                        <td className="p-4 text-slate-700">{res.checkIn}</td>
                        <td className="p-4 text-slate-700">{res.checkOut}</td>
                        <td className="p-4 text-right font-black text-indigo-700">${res.totalAmount.toLocaleString()}</td>
                        <td className="p-4 text-right">
                            <div className="flex justify-end items-center gap-2">
                                {res.status === ReservationStatus.CONFIRMED && (
                                    <button onClick={() => updateReservationStatus(res.id, ReservationStatus.CHECKED_IN)} className="text-xs bg-emerald-600 text-white px-3 py-2 rounded-lg font-bold hover:bg-emerald-700 transition-colors shadow-sm mr-2" title="Hacer Check-In">Check-In</button>
                                )}
                                <button onClick={() => handleOpenEdit(res)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors border border-indigo-100" title="Editar Reserva">
                                    <Edit size={16} />
                                </button>
                                <button onClick={() => handleRequestDelete(res.id)} className="p-2 text-rose-600 hover:bg-rose-50 rounded-lg transition-colors border border-rose-100" title="Eliminar Reserva">
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        </td>
                    </tr>
                  );
              })}
            </tbody>
          </table>
          {filteredReservations.length === 0 && <div className="p-12 text-center text-slate-500 font-medium">No se encontraron reservas registradas.</div>}
        </div>
      </div>

      {/* Modal Agregar/Editar */}
      {showModal && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[100] p-4 overflow-y-auto">
              <div className="bg-white rounded-3xl w-full max-w-2xl max-h-[95vh] overflow-y-auto shadow-2xl border border-slate-200 animate-in fade-in zoom-in duration-200">
                  <div className="p-6 border-b border-slate-200 flex justify-between items-center sticky top-0 bg-white z-10">
                      <h3 className="text-2xl font-black text-slate-900">{editingResId ? 'Modificar Reserva' : 'Nueva Reserva'}</h3>
                      <button onClick={() => { setShowModal(false); resetForm(); }} className="text-slate-500 hover:text-slate-900 bg-slate-100 p-2 rounded-full transition-colors"><X size={24}/></button>
                  </div>
                  <div className="p-8 space-y-8">
                       <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                           <MiniCalendar label="Fecha de Entrada" selectedDate={dates.checkIn} onChange={(d) => setDates(prev => ({ ...prev, checkIn: d }))} />
                           <MiniCalendar label="Fecha de Salida" selectedDate={dates.checkOut} onChange={(d) => setDates(prev => ({ ...prev, checkOut: d }))} />
                       </div>

                       <div className="space-y-6">
                            <div>
                                <label className="block text-sm font-black text-slate-800 mb-3 uppercase tracking-wider">Seleccionar Departamento</label>
                                <select 
                                    className="w-full border-2 border-slate-200 rounded-2xl p-4 bg-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none text-slate-900 font-bold transition-all appearance-none cursor-pointer" 
                                    value={selectedRoomId} 
                                    onChange={(e) => setSelectedRoomId(e.target.value)}
                                >
                                        <option value="" className="text-slate-400">Seleccione un departamento...</option>
                                        {editingResId && !availableRooms.some(r => r.id === selectedRoomId) && (
                                            <option value={selectedRoomId}>{rooms.find(r => r.id === selectedRoomId)?.number} (Seleccionado)</option>
                                        )}
                                        {availableRooms.map(room => (<option key={room.id} value={room.id} className="text-slate-900 font-medium">{room.number} - {room.type}</option>))}
                                </select>
                            </div>

                            {/* SELECTOR DE TARIFA SEGÚN OCUPACIÓN */}
                            {selectedRoomId && (
                                <div className="bg-slate-50 p-6 rounded-3xl border-2 border-slate-100">
                                    <label className="block text-sm font-black text-slate-800 mb-4 uppercase tracking-wider">Tarifa según ocupación</label>
                                    <div className="grid grid-cols-2 gap-4">
                                        <button 
                                            onClick={() => setOccupancyType('full')}
                                            className={`p-4 rounded-2xl border-2 flex flex-col items-center gap-2 transition-all ${occupancyType === 'full' ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-600 hover:border-indigo-200'}`}
                                        >
                                            <Home size={24} />
                                            <span className="font-black text-sm uppercase">Cabaña Completa</span>
                                            <span className={`text-lg font-black ${occupancyType === 'full' ? 'text-indigo-100' : 'text-indigo-600'}`}>
                                                ${rooms.find(r => r.id === selectedRoomId)?.pricePerNight}/noche
                                            </span>
                                        </button>
                                        <button 
                                            onClick={() => setOccupancyType('2pax')}
                                            className={`p-4 rounded-2xl border-2 flex flex-col items-center gap-2 transition-all ${occupancyType === '2pax' ? 'bg-amber-500 border-amber-500 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-600 hover:border-amber-200'}`}
                                        >
                                            <Users2 size={24} />
                                            <span className="font-black text-sm uppercase">Tarifa 2 Personas</span>
                                            <span className={`text-lg font-black ${occupancyType === '2pax' ? 'text-amber-50' : 'text-amber-600'}`}>
                                                ${rooms.find(r => r.id === selectedRoomId)?.pricePerNight2Pax || rooms.find(r => r.id === selectedRoomId)?.pricePerNight}/noche
                                            </span>
                                        </button>
                                    </div>
                                </div>
                            )}

                            <div className="border-t-2 border-slate-100 pt-6">
                                <div className="flex justify-between items-center mb-4">
                                    <label className="block text-sm font-black text-slate-800 uppercase tracking-wider">Información del Cliente</label>
                                    <button 
                                        onClick={() => setIsAddingClient(!isAddingClient)} 
                                        className={`text-xs flex items-center font-black px-4 py-2 rounded-xl transition-all ${isAddingClient ? 'bg-rose-100 text-rose-700' : 'bg-indigo-100 text-indigo-700 hover:bg-indigo-200'}`}
                                    >
                                        {isAddingClient ? <X size={14} className="mr-1.5" /> : <UserPlus size={14} className="mr-1.5" />}
                                        {isAddingClient ? 'Cancelar' : 'Nuevo Cliente'}
                                    </button>
                                </div>

                                {!isAddingClient ? (
                                    <select 
                                        className="w-full border-2 border-slate-200 rounded-2xl p-4 bg-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none text-slate-900 font-bold transition-all cursor-pointer" 
                                        value={selectedClientId} 
                                        onChange={e => setSelectedClientId(e.target.value)}
                                    >
                                            <option value="" className="text-slate-400">Seleccionar cliente existente...</option>
                                            {clients.map(c => <option key={c.id} value={c.id} className="text-slate-900 font-medium">{c.firstName} {c.lastName} (DNI: {c.documentNumber})</option>)}
                                    </select>
                                ) : (
                                    <div className="bg-slate-50 p-6 rounded-2xl border-2 border-indigo-100 space-y-4">
                                        <div className="grid grid-cols-2 gap-4">
                                            <div className="space-y-1">
                                                <p className="text-[10px] font-black text-slate-500 uppercase ml-1">Nombre</p>
                                                <input 
                                                    type="text" 
                                                    placeholder="Nombre..." 
                                                    className="w-full p-3.5 rounded-xl border-2 border-slate-200 text-slate-900 font-bold outline-none focus:border-indigo-500 bg-white"
                                                    value={newClientData.firstName}
                                                    onChange={e => setNewClientData({...newClientData, firstName: e.target.value})}
                                                />
                                            </div>
                                            <div className="space-y-1">
                                                <p className="text-[10px] font-black text-slate-500 uppercase ml-1">Apellido</p>
                                                <input 
                                                    type="text" 
                                                    placeholder="Apellido..." 
                                                    className="w-full p-3.5 rounded-xl border-2 border-slate-200 text-slate-900 font-bold outline-none focus:border-indigo-500 bg-white"
                                                    value={newClientData.lastName}
                                                    onChange={e => setNewClientData({...newClientData, lastName: e.target.value})}
                                                />
                                            </div>
                                        </div>
                                        <div className="grid grid-cols-2 gap-4">
                                            <div className="space-y-1">
                                                <p className="text-[10px] font-black text-slate-500 uppercase ml-1">DNI / Pasaporte</p>
                                                <input 
                                                    type="text" 
                                                    placeholder="Documento..." 
                                                    className="w-full p-3.5 rounded-xl border-2 border-slate-200 text-slate-900 font-bold outline-none focus:border-indigo-500 bg-white"
                                                    value={newClientData.documentNumber}
                                                    onChange={e => setNewClientData({...newClientData, documentNumber: e.target.value})}
                                                />
                                            </div>
                                            <div className="space-y-1">
                                                <p className="text-[10px] font-black text-slate-500 uppercase ml-1">Teléfono</p>
                                                <input 
                                                    type="text" 
                                                    placeholder="WhatsApp / Celular..." 
                                                    className="w-full p-3.5 rounded-xl border-2 border-slate-200 text-slate-900 font-bold outline-none focus:border-indigo-500 bg-white"
                                                    value={newClientData.phone}
                                                    onChange={e => setNewClientData({...newClientData, phone: e.target.value})}
                                                />
                                            </div>
                                        </div>
                                        <button 
                                            onClick={handleQuickAddClient}
                                            className="w-full bg-emerald-600 text-white py-3.5 rounded-xl text-sm font-black flex justify-center items-center hover:bg-emerald-700 transition-all shadow-md active:scale-95"
                                        >
                                            <Check size={18} className="mr-2" /> Registrar y Seleccionar Cliente
                                        </button>
                                    </div>
                                )}
                            </div>

                            <div className="bg-indigo-50/50 p-6 rounded-2xl border-2 border-indigo-100/50">
                                <label className="block text-sm font-black text-indigo-900 mb-3 uppercase tracking-wider">Monto de Seña ($)</label>
                                <div className="relative">
                                    <span className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-600 font-black text-xl">$</span>
                                    <input 
                                        type="number" 
                                        className="w-full border-2 border-indigo-200 rounded-2xl p-4 pl-10 bg-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none text-slate-900 font-black text-2xl transition-all" 
                                        placeholder="0.00"
                                        value={deposit} 
                                        onChange={e => setDeposit(Number(e.target.value))} 
                                    />
                                </div>
                                <p className="text-[10px] text-indigo-500 mt-2 font-bold italic">* Adelanto pagado por el cliente para asegurar la fecha.</p>
                            </div>
                       </div>
                  </div>
                  <div className="p-8 border-t-2 border-slate-100 bg-slate-50 sticky bottom-0 flex flex-col sm:flex-row gap-4">
                      <button 
                        onClick={() => { setShowModal(false); resetForm(); }} 
                        className="flex-1 py-4 text-slate-600 font-black hover:bg-slate-200 rounded-2xl transition-colors border-2 border-transparent"
                      >
                        Cancelar
                      </button>
                      <button 
                        onClick={handleSaveReservation} 
                        className="flex-[2] py-4 bg-indigo-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-indigo-200 hover:bg-indigo-700 transition-all transform active:scale-95 flex items-center justify-center"
                      >
                        <Check size={24} className="mr-2" /> {editingResId ? 'Guardar Cambios' : 'Confirmar Reserva'}
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Modal de Confirmación de Eliminación */}
      {showDeleteModal && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[110] p-4">
              <div className="bg-white p-8 rounded-3xl w-full max-w-sm shadow-2xl text-center border border-slate-200 animate-in fade-in zoom-in duration-200">
                  <div className="w-20 h-20 bg-rose-100 rounded-full flex items-center justify-center mx-auto mb-6 text-rose-600">
                      <AlertTriangle size={40} />
                  </div>
                  <h3 className="text-2xl font-black text-slate-900 mb-2">¿Eliminar Reserva?</h3>
                  <p className="text-slate-500 mb-8 font-medium">
                      Esta acción es permanente. Se liberará la fecha seleccionada en el calendario.
                  </p>

                  <div className="flex gap-4 justify-center">
                      <button 
                          onClick={() => setShowDeleteModal(false)}
                          className="flex-1 py-3.5 bg-slate-100 text-slate-700 rounded-xl font-black hover:bg-slate-200 transition-colors"
                      >
                          Cancelar
                      </button>
                      <button 
                          onClick={handleConfirmDelete}
                          className="flex-1 py-3.5 bg-rose-600 text-white rounded-xl font-black shadow-lg shadow-rose-200 hover:bg-rose-700 transition-all active:scale-95"
                      >
                          Sí, Borrar
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Bookings;

