import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { ReservationStatus, Room, Client, PaymentStatus, Reservation } from '../types';
import { Search, Plus, X, ChevronLeft, ChevronRight, UserPlus, Check, Edit, Trash2, AlertTriangle, Home, DollarSign } from 'lucide-react';

const MiniCalendar = ({ selectedDate, onChange, label }: { selectedDate: string, onChange: (date: string) => void, label: string }) => {
    const [viewDate, setViewDate] = useState(selectedDate ? new Date(selectedDate) : new Date());
    const today = new Date(); today.setHours(0, 0, 0, 0);

    useEffect(() => {
        if (selectedDate) {
            const [y, m, d] = selectedDate.split('-').map(Number);
            setViewDate(new Date(y, m - 1, d));
        }
    }, [selectedDate]);

    const getDaysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
    const getFirstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

    const year = viewDate.getFullYear();
    const month = viewDate.getMonth();
    const daysInMonth = getDaysInMonth(year, month);
    const startDay = getFirstDayOfMonth(year, month);

    const handlePrevMonth = (e: React.MouseEvent) => { e.preventDefault(); setViewDate(new Date(year, month - 1, 1)); };
    const handleNextMonth = (e: React.MouseEvent) => { e.preventDefault(); setViewDate(new Date(year, month + 1, 1)); };

    const handleDayClick = (day: number, isPast: boolean) => {
        if (isPast) return;
        const m = (month + 1).toString().padStart(2, '0');
        const d = day.toString().padStart(2, '0');
        onChange(`${year}-${m}-${d}`);
    };

    const monthNames = ["Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"];

    return (
        <div className="border border-slate-300 rounded-lg p-3 bg-white w-full shadow-sm">
            <label className="block text-sm font-bold text-slate-800 mb-2">{label}</label>
            <div className="flex justify-between items-center mb-2 bg-slate-100 p-1.5 rounded">
                <button onClick={handlePrevMonth} className="p-1 hover:bg-white rounded text-slate-700 transition-colors"><ChevronLeft size={16} /></button>
                <span className="font-bold text-sm text-slate-900">{monthNames[month]} {year}</span>
                <button onClick={handleNextMonth} className="p-1 hover:bg-white rounded text-slate-700 transition-colors"><ChevronRight size={16} /></button>
            </div>
            <div className="grid grid-cols-7 gap-1 text-center">
                {['D','L','M','M','J','V','S'].map((d, i) => (<div key={i} className="text-[10px] text-slate-500 font-black">{d}</div>))}
                {Array.from({ length: startDay }).map((_, i) => (<div key={`empty-${i}`} />))}
                {Array.from({ length: daysInMonth }).map((_, i) => {
                    const day = i + 1;
                    const dateToCheck = new Date(year, month, day);
                    const isPast = dateToCheck < today;
                    const dateStr = `${year}-${(month + 1).toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
                    const isSelected = selectedDate === dateStr;
                    return (
                        <button key={day} type="button" onClick={() => handleDayClick(day, isPast)} disabled={isPast}
                            className={`h-7 w-7 text-xs rounded-full flex items-center justify-center transition-all ${isSelected ? 'bg-indigo-600 text-white font-bold' : isPast ? 'text-slate-300 cursor-not-allowed' : 'text-slate-800 font-medium hover:bg-indigo-100'}`}
                        >{day}</button>
                    )
                })}
            </div>
        </div>
    );
};

const Bookings: React.FC = () => {
  const { reservations, rooms, clients, updateReservationStatus, addReservation, updateReservation, deleteReservation, addClient } = useApp();
  const [filter, setFilter] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [resToDeleteId, setResToDeleteId] = useState<string | null>(null);

  const [editingResId, setEditingResId] = useState<string | null>(null);
  const [dates, setDates] = useState({ checkIn: '', checkOut: '' });
  const [availableRooms, setAvailableRooms] = useState<Room[]>([]);
  const [selectedRoomId, setSelectedRoomId] = useState('');
  const [selectedClientId, setSelectedClientId] = useState('');
  const [totalPrice, setTotalPrice] = useState(0); // Ahora manual
  const [deposit, setDeposit] = useState(0);

  const [isAddingClient, setIsAddingClient] = useState(false);
  const [newClientData, setNewClientData] = useState<Partial<Client>>({
      firstName: '', lastName: '', platform: '', phone: ''
  });

  useEffect(() => {
    if (dates.checkIn && dates.checkOut) {
        const start = new Date(dates.checkIn + 'T00:00:00');
        const end = new Date(dates.checkOut + 'T00:00:00');
        const available = rooms.filter(room => {
            return !reservations.some(res => {
                if (editingResId && res.id === editingResId) return false;
                if (res.roomId !== room.id || res.status === ReservationStatus.CANCELLED) return false;
                const resStart = new Date(res.checkIn + 'T00:00:00');
                const resEnd = new Date(res.checkOut + 'T00:00:00');
                return start < resEnd && end > resStart;
            });
        });
        setAvailableRooms(available);
    }
  }, [dates, reservations, rooms, editingResId]);

  const resetForm = () => {
    setDates({ checkIn: '', checkOut: '' });
    setSelectedRoomId('');
    setSelectedClientId('');
    setTotalPrice(0);
    setDeposit(0);
    setEditingResId(null);
    setIsAddingClient(false);
  };

  const handleOpenEdit = (res: Reservation) => {
    setEditingResId(res.id);
    setDates({ checkIn: res.checkIn, checkOut: res.checkOut });
    setSelectedRoomId(res.roomId);
    setSelectedClientId(res.clientId);
    setTotalPrice(res.totalAmount);
    setDeposit(res.deposit || 0);
    setShowModal(true);
  };

  const handleSaveReservation = () => {
     if(!selectedRoomId || !selectedClientId || !dates.checkIn || !dates.checkOut) return alert("Complete todos los campos.");

     const reservationData: Reservation = {
         id: editingResId || `R-${Date.now().toString().slice(-4)}`,
         clientId: selectedClientId,
         roomId: selectedRoomId,
         checkIn: dates.checkIn,
         checkOut: dates.checkOut,
         status: editingResId ? (reservations.find(r => r.id === editingResId)?.status || ReservationStatus.CONFIRMED) : ReservationStatus.CONFIRMED,
         totalAmount: totalPrice,
         deposit: deposit,
         paymentStatus: PaymentStatus.PENDING,
         storeCharges: editingResId ? (reservations.find(r => r.id === editingResId)?.storeCharges || 0) : 0
     };

     if (editingResId) updateReservation(reservationData);
     else addReservation(reservationData);

     setShowModal(false);
     resetForm();
  };

  const handleQuickAddClient = () => {
      if (!newClientData.firstName || !newClientData.lastName || !newClientData.platform) {
          alert("Complete Nombre, Apellido y Plataforma."); return;
      }
      const newId = `c-${Date.now()}`;
      addClient({ ...newClientData, id: newId } as Client);
      setSelectedClientId(newId);
      setIsAddingClient(false);
      setNewClientData({ firstName: '', lastName: '', platform: '', phone: '' });
  };

  // Filtrado y Ordenamiento por Check-In
  const filteredReservations = reservations
    .filter(res => {
      const client = clients.find(c => c.id === res.clientId);
      const fullName = `${client?.lastName}, ${client?.firstName}`.toLowerCase();
      const matchesSearch = fullName.includes(searchTerm.toLowerCase()) || res.id.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = filter === 'all' || res.status === filter;
      return matchesSearch && matchesStatus;
    })
    .sort((a, b) => new Date(a.checkIn).getTime() - new Date(b.checkIn).getTime());

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-3xl font-bold text-slate-900">Reservas</h2>
        <button onClick={() => { resetForm(); setShowModal(true); }} className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl flex items-center hover:bg-indigo-700 transition shadow-lg shadow-indigo-100 font-bold">
          <Plus size={18} className="mr-2" /> Nueva Reserva
        </button>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-500" size={18} />
          <input 
            type="text" 
            placeholder="Buscar por cliente (Apellido, Nombre) o ID..." 
            className="w-full pl-10 pr-4 py-2.5 border border-slate-300 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-slate-900 font-medium transition-all bg-white" 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <select className="border border-slate-300 rounded-xl py-2 px-4 outline-none focus:ring-2 focus:ring-indigo-500 text-slate-900 font-bold bg-white" value={filter} onChange={(e) => setFilter(e.target.value)}>
            <option value="all">Todos los estados</option>
            <option value={ReservationStatus.CONFIRMED}>Confirmadas</option>
            <option value={ReservationStatus.CHECKED_IN}>Check-In</option>
        </select>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-100 text-slate-700 text-xs uppercase tracking-widest">
                <th className="p-4 font-black">ID</th>
                <th className="p-4 font-black">Cliente</th>
                <th className="p-4 font-black">Depto</th>
                <th className="p-4 font-black">Check-In</th>
                <th className="p-4 font-black">Check-Out</th>
                <th className="p-4 font-black text-right">Monto</th>
                <th className="p-4 font-black text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredReservations.map((res) => {
                  const client = clients.find(c => c.id === res.clientId);
                  const room = rooms.find(r => r.id === res.roomId);
                  return (
                    <tr key={res.id} className="hover:bg-indigo-50/30 transition text-sm">
                        <td className="p-4 font-bold text-slate-900">#{res.id}</td>
                        <td className="p-4 text-slate-800 font-medium">
                            <span className="font-black">{client?.lastName}</span>, {client?.firstName}
                            <div className="text-[10px] text-slate-500 uppercase font-bold tracking-tighter">Vía: {client?.platform}</div>
                        </td>
                        <td className="p-4 font-bold text-slate-900">{room?.number}</td>
                        <td className="p-4 text-slate-700 font-bold">{res.checkIn}</td>
                        <td className="p-4 text-slate-700">{res.checkOut}</td>
                        <td className="p-4 text-right font-black text-indigo-700">${res.totalAmount.toLocaleString()}</td>
                        <td className="p-4 text-right">
                            <div className="flex justify-end items-center gap-2">
                                {res.status === ReservationStatus.CONFIRMED && (
                                    <button onClick={() => updateReservationStatus(res.id, ReservationStatus.CHECKED_IN)} className="text-xs bg-emerald-600 text-white px-3 py-2 rounded-lg font-bold">Check-In</button>
                                )}
                                <button onClick={() => handleOpenEdit(res)} className="p-2 text-indigo-600 bg-indigo-50 rounded-lg"><Edit size={16} /></button>
                                <button onClick={() => { setResToDeleteId(res.id); setShowDeleteModal(true); }} className="p-2 text-rose-600 bg-rose-50 rounded-lg"><Trash2 size={16} /></button>
                            </div>
                        </td>
                    </tr>
                  );
              })}
            </tbody>
          </table>
          {filteredReservations.length === 0 && <div className="p-12 text-center text-slate-500 font-medium">No se encontraron resultados.</div>}
        </div>
      </div>

      {showModal && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[100] p-4 overflow-y-auto">
              <div className="bg-white rounded-3xl w-full max-w-2xl max-h-[95vh] overflow-y-auto shadow-2xl border border-slate-200">
                  <div className="p-6 border-b border-slate-200 flex justify-between items-center sticky top-0 bg-white z-10">
                      <h3 className="text-2xl font-black text-slate-900">{editingResId ? 'Modificar Reserva' : 'Nueva Reserva'}</h3>
                      <button onClick={() => { setShowModal(false); resetForm(); }} className="text-slate-500 hover:text-slate-900 bg-slate-100 p-2 rounded-full"><X size={24}/></button>
                  </div>
                  <div className="p-8 space-y-8">
                       <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                           <MiniCalendar label="Fecha de Entrada" selectedDate={dates.checkIn} onChange={(d) => setDates(prev => ({ ...prev, checkIn: d }))} />
                           <MiniCalendar label="Fecha de Salida" selectedDate={dates.checkOut} onChange={(d) => setDates(prev => ({ ...prev, checkOut: d }))} />
                       </div>

                       <div className="space-y-6">
                            <div>
                                <label className="block text-sm font-black text-slate-800 mb-3 uppercase tracking-wider">Seleccionar Departamento</label>
                                <select className="w-full border-2 border-slate-200 rounded-2xl p-4 bg-white text-slate-900 font-bold outline-none" value={selectedRoomId} onChange={(e) => setSelectedRoomId(e.target.value)}>
                                        <option value="">Seleccione...</option>
                                        {availableRooms.map(room => (<option key={room.id} value={room.id}>{room.number} - {room.type}</option>))}
                                </select>
                            </div>

                            <div className="border-t-2 border-slate-100 pt-6">
                                <div className="flex justify-between items-center mb-4">
                                    <label className="block text-sm font-black text-slate-800 uppercase tracking-wider">Información del Cliente</label>
                                    <button onClick={() => setIsAddingClient(!isAddingClient)} className={`text-xs flex items-center font-black px-4 py-2 rounded-xl ${isAddingClient ? 'bg-rose-100 text-rose-700' : 'bg-indigo-100 text-indigo-700'}`}>
                                        {isAddingClient ? 'Cancelar' : 'Nuevo Cliente'}
                                    </button>
                                </div>

                                {!isAddingClient ? (
                                    <select className="w-full border-2 border-slate-200 rounded-2xl p-4 bg-white text-slate-900 font-bold" value={selectedClientId} onChange={e => setSelectedClientId(e.target.value)}>
                                            <option value="">Seleccionar cliente...</option>
                                            {clients.map(c => <option key={c.id} value={c.id}>{c.lastName}, {c.firstName} ({c.platform})</option>)}
                                    </select>
                                ) : (
                                    <div className="bg-slate-50 p-6 rounded-2xl border-2 border-indigo-100 space-y-4">
                                        <div className="grid grid-cols-2 gap-4">
                                            <input type="text" placeholder="Nombre" className="w-full p-3.5 rounded-xl border-2 border-slate-200 font-bold" value={newClientData.firstName} onChange={e => setNewClientData({...newClientData, firstName: e.target.value})} />
                                            <input type="text" placeholder="Apellido" className="w-full p-3.5 rounded-xl border-2 border-slate-200 font-bold" value={newClientData.lastName} onChange={e => setNewClientData({...newClientData, lastName: e.target.value})} />
                                        </div>
                                        <div className="grid grid-cols-2 gap-4">
                                            <input type="text" placeholder="Plataforma (Airbnb, Booking, etc.)" className="w-full p-3.5 rounded-xl border-2 border-slate-200 font-bold" value={newClientData.platform} onChange={e => setNewClientData({...newClientData, platform: e.target.value})} />
                                            <input type="text" placeholder="WhatsApp / Celular" className="w-full p-3.5 rounded-xl border-2 border-slate-200 font-bold" value={newClientData.phone} onChange={e => setNewClientData({...newClientData, phone: e.target.value})} />
                                        </div>
                                        <button onClick={handleQuickAddClient} className="w-full bg-emerald-600 text-white py-3.5 rounded-xl text-sm font-black">Registrar Cliente</button>
                                    </div>
                                )}
                            </div>

                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                                <div className="bg-indigo-50/50 p-6 rounded-2xl border-2 border-indigo-100/50">
                                    <label className="block text-sm font-black text-indigo-900 mb-3 uppercase tracking-wider">Precio Total Estancia ($)</label>
                                    <div className="relative">
                                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-600 font-black text-xl">$</span>
                                        <input type="number" className="w-full border-2 border-indigo-200 rounded-2xl p-4 pl-10 bg-white text-slate-900 font-black text-2xl" placeholder="0.00" value={totalPrice} onChange={e => setTotalPrice(Number(e.target.value))} />
                                    </div>
                                </div>
                                <div className="bg-amber-50/50 p-6 rounded-2xl border-2 border-amber-100/50">
                                    <label className="block text-sm font-black text-amber-900 mb-3 uppercase tracking-wider">Monto de Seña ($)</label>
                                    <div className="relative">
                                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-amber-600 font-black text-xl">$</span>
                                        <input type="number" className="w-full border-2 border-amber-200 rounded-2xl p-4 pl-10 bg-white text-slate-900 font-black text-2xl" placeholder="0.00" value={deposit} onChange={e => setDeposit(Number(e.target.value))} />
                                    </div>
                                </div>
                            </div>
                       </div>
                  </div>
                  <div className="p-8 border-t-2 border-slate-100 bg-slate-50 sticky bottom-0 flex gap-4">
                      <button onClick={() => { setShowModal(false); resetForm(); }} className="flex-1 py-4 text-slate-600 font-black">Cancelar</button>
                      <button onClick={handleSaveReservation} className="flex-[2] py-4 bg-indigo-600 text-white rounded-2xl font-black text-lg">Confirmar</button>
                  </div>
              </div>
          </div>
      )}

      {showDeleteModal && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[110] p-4">
              <div className="bg-white p-8 rounded-3xl w-full max-w-sm shadow-2xl text-center border border-slate-200">
                  <AlertTriangle size={40} className="mx-auto text-rose-600 mb-6" />
                  <h3 className="text-2xl font-black text-slate-900 mb-2 w-full text-center">¿Eliminar Reserva?</h3>
                  <div className="flex gap-4 mt-8">
                      <button onClick={() => setShowDeleteModal(false)} className="flex-1 py-3.5 bg-slate-100 text-slate-700 rounded-xl font-black">No</button>
                      <button onClick={() => { deleteReservation(resToDeleteId!); setShowDeleteModal(false); }} className="flex-1 py-3.5 bg-rose-600 text-white rounded-xl font-black">Borrar</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

