export default Today;

import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { Room, Client, Product, Reservation, Sale, RoomStatus, ReservationStatus, MaintenanceItem, User, UserRole } from '../types';
import { INITIAL_ROOMS, INITIAL_CLIENTS, INITIAL_PRODUCTS, INITIAL_RESERVATIONS, INITIAL_MAINTENANCE_ITEMS } from '../constants';

const INITIAL_USERS: User[] = [
  { id: 'u1', name: 'Admin General', role: 'admin' },
  { id: 'u2', name: 'Recepcionista', role: 'receptionist' },
];

interface AppContextType {
  rooms: Room[];
  clients: Client[];
  products: Product[];
  maintenanceItems: MaintenanceItem[];
  reservations: Reservation[];
  sales: Sale[];
  currentUser: User;
  switchUser: (role: UserRole) => void;
  updateRoomStatus: (roomId: string, status: RoomStatus) => void;
  addRoom: (room: Room) => void;
  updateRoom: (room: Room) => void;
  deleteRoom: (roomId: string) => void;
  addClient: (client: Client) => void;
  deleteClient: (clientId: string) => void;
  addReservation: (reservation: Reservation) => void;
  updateReservation: (reservation: Reservation) => void;
  deleteReservation: (reservationId: string) => void;
  updateReservationStatus: (reservationId: string, status: ReservationStatus) => void;
  addSale: (sale: Sale) => void;
  addProduct: (product: Product) => void;
  deleteProduct: (productId: string) => void;
  updateProductStock: (productId: string, quantity: number) => void;
  addMaintenanceItem: (item: MaintenanceItem) => void;
  deleteMaintenanceItem: (itemId: string) => void;
  updateMaintenanceStock: (itemId: string, quantity: number) => void;
  getRoomById: (id: string) => Room | undefined;
  getClientById: (id: string) => Client | undefined;
  restoreBackup: (data: any) => void; // Nueva función
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const loadFromStorage = <T,>(key: string, initialValue: T): T => {
  try {
    const saved = localStorage.getItem(key);
    if (saved) return JSON.parse(saved);
  } catch (error) {
    console.error(`Error loading ${key}`, error);
  }
  return initialValue;
};

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User>(INITIAL_USERS[0]);
  const [rooms, setRooms] = useState<Room[]>(() => loadFromStorage('AROMA_ROOMS', INITIAL_ROOMS));
  const [clients, setClients] = useState<Client[]>(() => loadFromStorage('AROMA_CLIENTS', INITIAL_CLIENTS));
  const [products, setProducts] = useState<Product[]>(() => loadFromStorage('AROMA_PRODUCTS', INITIAL_PRODUCTS));
  const [maintenanceItems, setMaintenanceItems] = useState<MaintenanceItem[]>(() => loadFromStorage('AROMA_MAINTENANCE', INITIAL_MAINTENANCE_ITEMS));
  const [reservations, setReservations] = useState<Reservation[]>(() => loadFromStorage('AROMA_RESERVATIONS', INITIAL_RESERVATIONS));
  const [sales, setSales] = useState<Sale[]>(() => loadFromStorage('AROMA_SALES', []));

  useEffect(() => { localStorage.setItem('AROMA_ROOMS', JSON.stringify(rooms)); }, [rooms]);
  useEffect(() => { localStorage.setItem('AROMA_CLIENTS', JSON.stringify(clients)); }, [clients]);
  useEffect(() => { localStorage.setItem('AROMA_PRODUCTS', JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem('AROMA_MAINTENANCE', JSON.stringify(maintenanceItems)); }, [maintenanceItems]);
  useEffect(() => { localStorage.setItem('AROMA_RESERVATIONS', JSON.stringify(reservations)); }, [reservations]);
  useEffect(() => { localStorage.setItem('AROMA_SALES', JSON.stringify(sales)); }, [sales]);

  const restoreBackup = (data: any) => {
    try {
      if (data.rooms) setRooms(data.rooms);
      if (data.clients) setClients(data.clients);
      if (data.products) setProducts(data.products);
      if (data.maintenanceItems || data.maintenance) setMaintenanceItems(data.maintenanceItems || data.maintenance);
      if (data.reservations) setReservations(data.reservations);
      if (data.sales) setSales(data.sales);

      // Forzar guardado inmediato
      if (data.rooms) localStorage.setItem('AROMA_ROOMS', JSON.stringify(data.rooms));
      if (data.clients) localStorage.setItem('AROMA_CLIENTS', JSON.stringify(data.clients));
      if (data.products) localStorage.setItem('AROMA_PRODUCTS', JSON.stringify(data.products));
      if (data.maintenanceItems || data.maintenance) localStorage.setItem('AROMA_MAINTENANCE', JSON.stringify(data.maintenanceItems || data.maintenance));
      if (data.reservations) localStorage.setItem('AROMA_RESERVATIONS', JSON.stringify(data.reservations));
      if (data.sales) localStorage.setItem('AROMA_SALES', JSON.stringify(data.sales));
    } catch (e) {
      console.error("Error restoring backup", e);
      throw e;
    }
  };

  const switchUser = (role: UserRole) => {
    const user = INITIAL_USERS.find(u => u.role === role);
    if (user) setCurrentUser(user);
  };

  const updateRoomStatus = (roomId: string, status: RoomStatus) => {
    setRooms(prev => prev.map(r => String(r.id) === String(roomId) ? { ...r, status } : r));
  };

  const addRoom = (room: Room) => { setRooms(prev => [...prev, room]); };
  const updateRoom = (updatedRoom: Room) => { setRooms(prev => prev.map(r => String(r.id) === String(updatedRoom.id) ? updatedRoom : r)); };
  const deleteRoom = (roomId: string) => { setRooms(prev => prev.filter(r => String(r.id) !== String(roomId))); };

  const addClient = (client: Client) => { setClients(prev => [...prev, client]); };
  const deleteClient = (clientId: string) => { setClients(prev => prev.filter(c => String(c.id) !== String(clientId))); };

  const addReservation = (reservation: Reservation) => {
    setReservations(prev => [...prev, reservation]);
  };

  const updateReservation = (updatedRes: Reservation) => {
    setReservations(prev => prev.map(r => String(r.id) === String(updatedRes.id) ? updatedRes : r));
  };

  const deleteReservation = (reservationId: string) => {
    setReservations(prev => prev.filter(r => String(r.id) !== String(reservationId)));
  };

  const updateReservationStatus = (reservationId: string, status: ReservationStatus) => {
    setReservations(prev => prev.map(r => {
        if (String(r.id) === String(reservationId)) {
            if (status === ReservationStatus.CHECKED_IN) updateRoomStatus(r.roomId, RoomStatus.OCCUPIED);
            else if (status === ReservationStatus.CHECKED_OUT) updateRoomStatus(r.roomId, RoomStatus.CLEANING);
            return { ...r, status };
        }
        return r;
    }));
  };

  const addSale = (sale: Sale) => {
    setSales(prev => [...prev, sale]);
    sale.items.forEach(item => {
        setProducts(prev => prev.map(p => String(p.id) === String(item.id) ? { ...p, stock: p.stock - item.quantity } : p));
    });
    if (sale.reservationId) {
        setReservations(prev => prev.map(r => String(r.id) === String(sale.reservationId) ? { ...r, storeCharges: (r.storeCharges || 0) + sale.total } : r));
    }
  };

  const addProduct = (product: Product) => { setProducts(prev => [...prev, product]); };
  const deleteProduct = (productId: string) => { setProducts(prev => prev.filter(p => String(p.id) !== String(productId))); };
  const updateProductStock = (productId: string, quantity: number) => {
    setProducts(prev => prev.map(p => String(p.id) === String(productId) ? { ...p, stock: p.stock + quantity } : p));
  };

  const addMaintenanceItem = (item: MaintenanceItem) => { setMaintenanceItems(prev => [...prev, item]); };
  const deleteMaintenanceItem = (itemId: string) => { setMaintenanceItems(prev => prev.filter(i => String(i.id) !== String(itemId))); };
  const updateMaintenanceStock = (itemId: string, quantity: number) => {
    setMaintenanceItems(prev => prev.map(item => String(item.id) === String(itemId) ? { ...item, stock: item.stock + quantity } : item));
  };

  const getRoomById = (id: string) => rooms.find(r => String(r.id) === String(id));
  const getClientById = (id: string) => clients.find(c => String(c.id) === String(id));

  return (
    <AppContext.Provider value={{
      rooms, clients, products, maintenanceItems, reservations, sales, currentUser, switchUser,
      updateRoomStatus, addRoom, updateRoom, deleteRoom, addClient, deleteClient, addReservation,
      updateReservation, deleteReservation, updateReservationStatus, addSale, addProduct, 
      deleteProduct, updateProductStock, addMaintenanceItem, deleteMaintenanceItem, 
      updateMaintenanceStock, getRoomById, getClientById, restoreBackup
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) throw new Error('useApp must be used within an AppProvider');
  return context;
};

import React, { useState, useRef } from 'react';
import { useApp } from '../context/AppContext';
import { Save, UserCircle, Building, CreditCard, Lock, Download, Upload, Database, AlertCircle, CheckCircle } from 'lucide-react';

const Settings: React.FC = () => {
  const { currentUser, switchUser, rooms, clients, products, maintenanceItems, reservations, sales, restoreBackup } = useApp();

  const [hotelName, setHotelName] = useState('Aroma a Vid');
  const [address, setAddress] = useState('Av. Del Sol 123, Montaña Alta');
  const [checkInTime, setCheckInTime] = useState('14:00');
  const [checkOutTime, setCheckOutTime] = useState('10:00');
  const [ivaRate, setIvaRate] = useState(21);
  const [currency, setCurrency] = useState('USD');

  const [showPinModal, setShowPinModal] = useState(false);
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSave = () => {
      setSuccessMessage(true);
      setTimeout(() => setSuccessMessage(false), 3000);
  };

  const handleAdminClick = () => {
    if (currentUser.role === 'admin') return;
    setShowPinModal(true);
    setPin('');
    setError('');
  };

  const verifyPin = () => {
    if (pin === '0209') {
        switchUser('admin');
        setShowPinModal(false);
    } else {
        setError('Contraseña incorrecta');
        setPin('');
    }
  };

  // --- LOGICA DE BACKUP MEJORADA ---
  const handleExportData = () => {
      // Exportamos los objetos reales del estado, no los strings de localStorage
      const dataToExport = {
          rooms,
          clients,
          products,
          maintenanceItems,
          reservations,
          sales,
          exportDate: new Date().toISOString(),
          version: "2.0"
      };

      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(dataToExport, null, 2));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", `copia_aroma_avid_${new Date().toISOString().split('T')[0]}.json`);
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  const handleImportClick = () => {
      fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const content = event.target?.result as string;
              const json = JSON.parse(content);

              // Verificamos compatibilidad (al menos habitaciones o clientes)
              if (!json.rooms && !json.clients && !json.reservations) {
                  alert("Error: El archivo no parece ser una copia de seguridad válida de Aroma a Vid.");
                  return;
              }

              if (window.confirm("ATENCIÓN: Esto reemplazará TODOS los datos actuales con los del archivo. ¿Desea continuar?")) {
                  // Si los datos en el JSON son strings (formato viejo), intentamos parsearlos
                  const normalizedData: any = {};
                  Object.keys(json).forEach(key => {
                      if (typeof json[key] === 'string' && (json[key].startsWith('[') || json[key].startsWith('{'))) {
                          try { normalizedData[key] = JSON.parse(json[key]); } catch { normalizedData[key] = json[key]; }
                      } else {
                          normalizedData[key] = json[key];
                      }
                  });

                  restoreBackup(normalizedData);
                  alert("Datos restaurados con éxito. La aplicación se reiniciará para aplicar los cambios.");
                  window.location.reload();
              }
          } catch (err) {
              console.error(err);
              alert("Error al leer el archivo. Asegúrese de que sea un archivo .json válido.");
          }
      };
      reader.readAsText(file);
      e.target.value = '';
  };

  return (
    <div className="space-y-6 relative pb-20">
      <div className="flex justify-between items-center">
        <h2 className="text-3xl font-bold text-slate-800">Configuración del Sistema</h2>
        {successMessage && (
            <div className="bg-emerald-100 text-emerald-700 px-4 py-2 rounded-lg flex items-center font-bold animate-in fade-in slide-in-from-top-2">
                <CheckCircle size={18} className="mr-2" /> Cambios guardados
            </div>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 md:col-span-2">
            <div className="flex items-center gap-3 mb-4 border-b border-slate-100 pb-3">
                <UserCircle className="text-indigo-600" size={24} />
                <h3 className="text-xl font-bold text-slate-800">Simulación de Usuario</h3>
            </div>
            <p className="text-sm text-slate-500 mb-4 font-medium">
                Alterne entre roles para verificar los permisos de acceso y funciones administrativas.
            </p>
            <div className="flex gap-4">
                <button 
                    onClick={handleAdminClick}
                    className={`flex-1 py-4 px-4 rounded-2xl border-2 text-sm font-black flex items-center justify-center transition-all ${currentUser.role === 'admin' ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg' : 'bg-white text-slate-600 border-slate-100 hover:bg-slate-50'}`}
                >
                    <Lock size={18} className="mr-2" />
                    Modo Administrador
                    {currentUser.role === 'admin' && <span className="ml-2 bg-indigo-400 text-white text-[10px] px-2 py-0.5 rounded-full uppercase">Activo</span>}
                </button>
                <button 
                    onClick={() => switchUser('receptionist')}
                    className={`flex-1 py-4 px-4 rounded-2xl border-2 text-sm font-black flex items-center justify-center transition-all ${currentUser.role === 'receptionist' ? 'bg-emerald-600 text-white border-emerald-600 shadow-lg' : 'bg-white text-slate-600 border-slate-100 hover:bg-slate-50'}`}
                >
                    Modo Recepcionista
                    {currentUser.role === 'receptionist' && <span className="ml-2 bg-emerald-400 text-white text-[10px] px-2 py-0.5 rounded-full uppercase">Activo</span>}
                </button>
            </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 md:col-span-2">
            <div className="flex items-center gap-3 mb-4 border-b border-slate-100 pb-3">
                <Database className="text-emerald-600" size={24} />
                <h3 className="text-xl font-bold text-slate-800">Respaldo y Restauración de Datos</h3>
            </div>

            <div className="bg-amber-50 border border-amber-100 p-5 rounded-2xl mb-6 flex items-start">
                 <AlertCircle className="text-amber-500 mt-1 mr-4 flex-shrink-0" size={24} />
                 <div>
                    <p className="text-sm text-amber-900 font-bold mb-1">Copia de Seguridad Crítica</p>
                    <p className="text-xs text-amber-800 leading-relaxed font-medium">
                        Los datos se almacenan localmente en su navegador. Si limpia el historial o cambia de dispositivo sin una copia, perderá sus reservas.
                        <strong> Descargue una copia semanalmente.</strong>
                    </p>
                 </div>
            </div>

            <div className="flex flex-col sm:flex-row gap-4">
                <button 
                    onClick={handleExportData}
                    className="flex-1 bg-slate-900 text-white py-4 px-4 rounded-2xl hover:bg-black transition flex items-center justify-center font-black shadow-lg"
                >
                    <Download size={20} className="mr-2" />
                    Descargar Copia (.json)
                </button>
                <button 
                    onClick={handleImportClick}
                    className="flex-1 bg-white border-2 border-slate-200 text-slate-700 py-4 px-4 rounded-2xl hover:bg-slate-50 transition flex items-center justify-center font-black"
                >
                    <Upload size={20} className="mr-2" />
                    Restaurar Datos
                </button>
                <input 
                    type="file" 
                    ref={fileInputRef}
                    onChange={handleFileChange}
                    accept=".json"
                    className="hidden"
                />
            </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <div className="flex items-center gap-3 mb-6">
                <Building className="text-indigo-600" size={24} />
                <h3 className="text-lg font-bold text-slate-800">Establecimiento</h3>
            </div>
            <div className="space-y-4">
                <div>
                    <label className="block text-[10px] font-black uppercase text-slate-500 mb-1 ml-1">Nombre</label>
                    <input type="text" className="w-full border-2 border-slate-100 rounded-xl p-3 text-sm font-bold bg-slate-50/50" value={hotelName} onChange={e => setHotelName(e.target.value)} />
                </div>
                <div>
                    <label className="block text-[10px] font-black uppercase text-slate-500 mb-1 ml-1">Dirección</label>
                    <input type="text" className="w-full border-2 border-slate-100 rounded-xl p-3 text-sm font-bold bg-slate-50/50" value={address} onChange={e => setAddress(e.target.value)} />
                </div>
            </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <div className="flex items-center gap-3 mb-6">
                <CreditCard className="text-indigo-600" size={24} />
                <h3 className="text-lg font-bold text-slate-800">Operaciones</h3>
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-[10px] font-black uppercase text-slate-500 mb-1 ml-1">Check-In</label>
                    <input type="time" className="w-full border-2 border-slate-100 rounded-xl p-3 text-sm font-bold bg-slate-50/50" value={checkInTime} onChange={e => setCheckInTime(e.target.value)} />
                </div>
                <div>
                    <label className="block text-[10px] font-black uppercase text-slate-500 mb-1 ml-1">Check-Out</label>
                    <input type="time" className="w-full border-2 border-slate-100 rounded-xl p-3 text-sm font-bold bg-slate-50/50" value={checkOutTime} onChange={e => setCheckOutTime(e.target.value)} />
                </div>
            </div>
        </div>

        <div className="md:col-span-2 flex justify-end pt-4">
            <button 
                onClick={handleSave}
                className="bg-indigo-600 text-white px-10 py-4 rounded-2xl hover:bg-indigo-700 flex items-center font-black shadow-xl shadow-indigo-100 transition-all active:scale-95"
            >
                <Save size={20} className="mr-2" />
                Guardar Configuración
            </button>
        </div>
      </div>

      {showPinModal && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm flex items-center justify-center z-[200]">
            <div className="bg-white p-10 rounded-3xl shadow-2xl w-full max-w-sm text-center animate-in zoom-in duration-200">
                <h3 className="text-2xl font-black text-slate-900 mb-2">Clave Maestra</h3>
                <p className="text-sm text-slate-500 mb-8 font-medium">Ingrese la contraseña de administrador</p>

                <input 
                    type="password" 
                    maxLength={4}
                    className="w-full text-center text-4xl tracking-[0.5em] font-black border-b-4 border-slate-200 focus:border-indigo-600 focus:outline-none py-4 mb-6 bg-transparent"
                    autoFocus
                    placeholder="••••"
                    value={pin}
                    onChange={(e) => setPin(e.target.value)}
                />

                {error && <p className="text-rose-500 text-xs font-black mb-6 uppercase tracking-widest">{error}</p>}

                <div className="flex gap-4">
                    <button 
                        onClick={() => setShowPinModal(false)}
                        className="flex-1 py-4 text-slate-400 font-black hover:bg-slate-100 rounded-2xl transition-colors"
                    >
                        Cancelar
                    </button>
                    <button 
                        onClick={verifyPin}
                        className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl hover:bg-indigo-700 font-black shadow-lg shadow-indigo-100"
                    >
                        Entrar
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default Settings;

import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { ReservationStatus, Room, Client, PaymentStatus, Reservation } from '../types';
import { Search, Plus, X, ChevronLeft, ChevronRight, UserPlus, Check, Edit, Trash2, AlertTriangle, Home, DollarSign } from 'lucide-react';

const MiniCalendar = ({ selectedDate, onChange, label }: { selectedDate: string, onChange: (date: string) => void, label: string }) => {
    const [viewDate, setViewDate] = useState(selectedDate ? new Date(selectedDate) : new Date());
    const today = new Date(); today.setHours(0, 0, 0, 0);

    useEffect(() => {
        if (selectedDate) {
            const [y, m, d] = selectedDate.split('-').map(Number);
            setViewDate(new Date(y, m - 1, d));
        }
    }, [selectedDate]);

    const getDaysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
    const getFirstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

    const year = viewDate.getFullYear();
    const month = viewDate.getMonth();
    const daysInMonth = getDaysInMonth(year, month);
    const startDay = getFirstDayOfMonth(year, month);

    const handlePrevMonth = (e: React.MouseEvent) => { e.preventDefault(); setViewDate(new Date(year, month - 1, 1)); };
    const handleNextMonth = (e: React.MouseEvent) => { e.preventDefault(); setViewDate(new Date(year, month + 1, 1)); };

    const handleDayClick = (day: number, isPast: boolean) => {
        if (isPast) return;
        const m = (month + 1).toString().padStart(2, '0');
        const d = day.toString().padStart(2, '0');
        onChange(`${year}-${m}-${d}`);
    };

    const monthNames = ["Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"];

    return (
        <div className="border border-slate-300 rounded-lg p-3 bg-white w-full shadow-sm">
            <label className="block text-sm font-bold text-slate-800 mb-2">{label}</label>
            <div className="flex justify-between items-center mb-2 bg-slate-100 p-1.5 rounded">
                <button onClick={handlePrevMonth} className="p-1 hover:bg-white rounded text-slate-700 transition-colors"><ChevronLeft size={16} /></button>
                <span className="font-bold text-sm text-slate-900">{monthNames[month]} {year}</span>
                <button onClick={handleNextMonth} className="p-1 hover:bg-white rounded text-slate-700 transition-colors"><ChevronRight size={16} /></button>
            </div>
            <div className="grid grid-cols-7 gap-1 text-center">
                {['D','L','M','M','J','V','S'].map((d, i) => (<div key={i} className="text-[10px] text-slate-500 font-black">{d}</div>))}
                {Array.from({ length: startDay }).map((_, i) => (<div key={`empty-${i}`} />))}
                {Array.from({ length: daysInMonth }).map((_, i) => {
                    const day = i + 1;
                    const dateToCheck = new Date(year, month, day);
                    const isPast = dateToCheck < today;
                    const dateStr = `${year}-${(month + 1).toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
                    const isSelected = selectedDate === dateStr;
                    return (
                        <button key={day} type="button" onClick={() => handleDayClick(day, isPast)} disabled={isPast}
                            className={`h-7 w-7 text-xs rounded-full flex items-center justify-center transition-all ${isSelected ? 'bg-indigo-600 text-white font-bold' : isPast ? 'text-slate-300 cursor-not-allowed' : 'text-slate-800 font-medium hover:bg-indigo-100'}`}
                        >{day}</button>
                    )
                })}
            </div>
        </div>
    );
};

const Bookings: React.FC = () => {
  const { reservations, rooms, clients, updateReservationStatus, addReservation, updateReservation, deleteReservation, addClient } = useApp();
  const [filter, setFilter] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [resToDeleteId, setResToDeleteId] = useState<string | null>(null);

  const [editingResId, setEditingResId] = useState<string | null>(null);
  const [dates, setDates] = useState({ checkIn: '', checkOut: '' });
  const [availableRooms, setAvailableRooms] = useState<Room[]>([]);
  const [selectedRoomId, setSelectedRoomId] = useState('');
  const [selectedClientId, setSelectedClientId] = useState('');
  const [totalPrice, setTotalPrice] = useState(0); 
  const [deposit, setDeposit] = useState(0);

  const [isAddingClient, setIsAddingClient] = useState(false);
  const [newClientData, setNewClientData] = useState<Partial<Client>>({
      firstName: '', lastName: '', platform: '', phone: ''
  });

  useEffect(() => {
    if (dates.checkIn && dates.checkOut) {
        const start = new Date(dates.checkIn + 'T00:00:00');
        const end = new Date(dates.checkOut + 'T00:00:00');
        const available = rooms.filter(room => {
            return !reservations.some(res => {
                if (editingResId && res.id === editingResId) return false;
                if (res.roomId !== room.id || res.status === ReservationStatus.CANCELLED) return false;
                const resStart = new Date(res.checkIn + 'T00:00:00');
                const resEnd = new Date(res.checkOut + 'T00:00:00');
                return start < resEnd && end > resStart;
            });
        });
        setAvailableRooms(available);
    }
  }, [dates, reservations, rooms, editingResId]);

  const resetForm = () => {
    setDates({ checkIn: '', checkOut: '' });
    setSelectedRoomId('');
    setSelectedClientId('');
    setTotalPrice(0);
    setDeposit(0);
    setEditingResId(null);
    setIsAddingClient(false);
  };

  const handleOpenEdit = (res: Reservation) => {
    setEditingResId(res.id);
    setDates({ checkIn: res.checkIn, checkOut: res.checkOut });
    setSelectedRoomId(res.roomId);
    setSelectedClientId(res.clientId);
    setTotalPrice(res.totalAmount);
    setDeposit(res.deposit || 0);
    setShowModal(true);
  };

  const handleSaveReservation = () => {
     if(!selectedRoomId || !selectedClientId || !dates.checkIn || !dates.checkOut) return alert("Complete todos los campos.");

     const reservationData: Reservation = {
         id: editingResId || `R-${Date.now().toString().slice(-4)}`,
         clientId: selectedClientId,
         roomId: selectedRoomId,
         checkIn: dates.checkIn,
         checkOut: dates.checkOut,
         status: editingResId ? (reservations.find(r => r.id === editingResId)?.status || ReservationStatus.CONFIRMED) : ReservationStatus.CONFIRMED,
         totalAmount: totalPrice,
         deposit: deposit,
         paymentStatus: PaymentStatus.PENDING,
         storeCharges: editingResId ? (reservations.find(r => r.id === editingResId)?.storeCharges || 0) : 0
     };

     if (editingResId) updateReservation(reservationData);
     else addReservation(reservationData);

     setShowModal(false);
     resetForm();
  };

  const handleQuickAddClient = () => {
      if (!newClientData.firstName || !newClientData.lastName || !newClientData.platform) {
          alert("Complete Nombre, Apellido y Plataforma."); return;
      }
      const newId = `c-${Date.now()}`;
      addClient({ ...newClientData, id: newId } as Client);
      setSelectedClientId(newId);
      setIsAddingClient(false);
      setNewClientData({ firstName: '', lastName: '', platform: '', phone: '' });
  };

  const filteredReservations = reservations
    .filter(res => {
      const client = clients.find(c => c.id === res.clientId);
      const fullName = `${client?.lastName}, ${client?.firstName}`.toLowerCase();
      const matchesSearch = fullName.includes(searchTerm.toLowerCase()) || res.id.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = filter === 'all' || res.status === filter;
      return matchesSearch && matchesStatus;
