  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-3xl font-bold text-slate-900">Reservas</h2>
        <button onClick={() => { resetForm(); setShowModal(true); }} className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl flex items-center hover:bg-indigo-700 transition shadow-lg shadow-indigo-100 font-bold">
          <Plus size={18} className="mr-2" /> Nueva Reserva
        </button>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-500" size={18} />
          <input 
            type="text" 
            placeholder="Buscar por cliente (Apellido, Nombre) o ID..." 
            className="w-full pl-10 pr-4 py-3 border-2 border-slate-100 rounded-2xl focus:border-indigo-500 outline-none !text-slate-900 font-bold transition-all !bg-white placeholder:text-slate-400" 
            style={{ backgroundColor: 'white !important', color: '#0f172a !important' }}
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <select className="border-2 border-slate-100 rounded-2xl py-2 px-4 outline-none focus:border-indigo-500 !text-slate-900 font-black !bg-white cursor-pointer" value={filter} onChange={(e) => setFilter(e.target.value)}>
            <option value="all">TODOS</option>
