                                <button onClick={() => { setResToDeleteId(res.id); setShowDeleteModal(true); }} className="p-2.5 text-rose-600 bg-rose-50 rounded-xl hover:bg-rose-100 transition"><Trash2 size={16} /></button>
                            </div>
                        </td>
