                                    <div className="relative">
                                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-amber-600 font-black text-xl">$</span>
                                        <input type="number" className="w-full border-2 border-amber-100 rounded-2xl p-4 pl-10 bg-white text-slate-900 font-black text-3xl outline-none" placeholder="0.00" value={deposit} onChange={e => setDeposit(Number(e.target.value))} />
