                       </div>
                  </div>
                  <div className="p-8 border-t-2 border-slate-100 bg-slate-50 sticky bottom-0 flex gap-4">
                      <button onClick={() => { setShowModal(false); resetForm(); }} className="flex-1 py-5 text-slate-400 font-black hover:bg-slate-200 rounded-2xl transition-colors">CANCELAR</button>
                      <button onClick={handleSaveReservation} className="flex-[2] py-5 bg-indigo-600 text-white rounded-2xl font-black text-xl shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition active:scale-95">CONFIRMAR RESERVA</button>
                  </div>
              </div>
          </div>
      )}

      {showDeleteModal && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[110] p-4">
              <div className="bg-white p-10 rounded-3xl w-full max-w-sm shadow-2xl text-center border border-slate-200 animate-in zoom-in duration-200">
                  <div className="w-20 h-20 bg-rose-100 rounded-full flex items-center justify-center mx-auto mb-6 text-rose-600">
                    <AlertTriangle size={40} />
