const Calendar: React.FC = () => {
  const { rooms, reservations, clients } = useApp();
  const [currentDate, setCurrentDate] = useState(new Date());
  const [showModal, setShowModal] = useState(false);
  const [editingResId, setEditingResId] = useState<string | null>(null);

  const getDaysInMonth = (date: Date) => new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
  const daysInMonth = getDaysInMonth(currentDate);
  const daysArray = Array.from({ length: daysInMonth }, (_, i) => i + 1);
  const monthName = currentDate.toLocaleString('es-ES', { month: 'long', year: 'numeric' });

  const changeMonth = (delta: number) => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + delta, 1));

  const getReservationForDay = (roomId: string, day: number): Reservation | undefined => {
    const targetDate = new Date(currentDate.getFullYear(), currentDate.getMonth(), day);
    targetDate.setHours(0, 0, 0, 0);
    return reservations.find(r => {
      if (r.roomId !== roomId || r.status === ReservationStatus.CANCELLED) return false;
      const [sY, sM, sD] = r.checkIn.split('-').map(Number);
      const [eY, eM, eD] = r.checkOut.split('-').map(Number);
      const sDate = new Date(sY, sM - 1, sD); sDate.setHours(0,0,0,0);
      const eDate = new Date(eY, eM - 1, eD); eDate.setHours(0,0,0,0);
      return targetDate >= sDate && targetDate <= eDate;
    });
  };

  const getCellStatus = (res: Reservation | undefined, day: number) => {
    if (!res) return 'bg-white';
    const targetDate = new Date(currentDate.getFullYear(), currentDate.getMonth(), day); targetDate.setHours(0, 0, 0, 0);
    const [sY, sM, sD] = res.checkIn.split('-').map(Number);
    const [eY, eM, eD] = res.checkOut.split('-').map(Number);
    const sDate = new Date(sY, sM - 1, sD); sDate.setHours(0,0,0,0);
    const eDate = new Date(eY, eM - 1, eD); eDate.setHours(0,0,0,0);
    if (targetDate.getTime() === sDate.getTime()) return 'bg-indigo-100 border-l-4 border-indigo-600';
    if (targetDate.getTime() === eDate.getTime()) return 'bg-slate-100';
    return 'bg-rose-100/50';
  };

  const handleDayClick = (roomId: string, day: number) => {
      const res = getReservationForDay(roomId, day);
      if (res) {
          setEditingResId(res.id);
          setShowModal(true);
      }
  };

  return (
