          <ShoppingBag size={16} className="mr-2" /> TIENDA
        </button>
        <button onClick={() => setActiveTab('maintenance')} className={`pb-4 px-2 flex items-center font-black text-xs uppercase tracking-widest transition-all ${activeTab === 'maintenance' ? 'border-b-4 border-indigo-600 text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}>
          <Wrench size={16} className="mr-2" /> MANTENIMIENTO
        </button>
