const Calendar: React.FC = () => {
  const { rooms, reservations, clients } = useApp();
  const [currentDate, setCurrentDate] = useState(new Date());
  const [showModal, setShowModal] = useState(false);
  const [editingResId, setEditingResId] = useState<string | null>(null);

  const getDaysInMonth = (date: Date) => new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
  const daysInMonth = getDaysInMonth(currentDate);
  const daysArray = Array.from({ length: daysInMonth }, (_, i) => i + 1);
  const monthName = currentDate.toLocaleString('es-ES', { month: 'long', year: 'numeric' });

  const changeMonth = (delta: number) => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + delta, 1));

  // Función mejorada para obtener qué sucede en una celda
  const getCellDetails = (roomId: string, day: number) => {
    const targetDate = new Date(currentDate.getFullYear(), currentDate.getMonth(), day);
    targetDate.setHours(0, 0, 0, 0);
    const dateStr = targetDate.toISOString().split('T')[0];

    // Reservas activas hoy
    const roomReservations = reservations.filter(r => r.roomId === roomId && r.status !== ReservationStatus.CANCELLED);

    const checkInRes = roomReservations.find(r => r.checkIn === dateStr);
    const checkOutRes = roomReservations.find(r => r.checkOut === dateStr);

    // Si no es ni entrada ni salida, ver si está "en medio" de una estancia
    const stayRes = roomReservations.find(r => {
        const s = new Date(r.checkIn + 'T00:00:00');
        const e = new Date(r.checkOut + 'T00:00:00');
        return targetDate > s && targetDate < e;
    });

    return { checkInRes, checkOutRes, stayRes };
  };

  const renderCellContent = (roomId: string, day: number) => {
    const { checkInRes, checkOutRes, stayRes } = getCellDetails(roomId, day);

    // Mitad y mitad (Rotación)
    if (checkInRes && checkOutRes) {
        return (
            <div 
                className="absolute inset-0 cursor-pointer group"
                style={{ background: 'linear-gradient(135deg, #f43f5e 50%, #10b981 50%)' }}
                onClick={() => handleDayClick(roomId, day)}
            >
                <div className="hidden group-hover:flex absolute inset-0 bg-black/10 items-center justify-center pointer-events-none">
                    <Edit size={14} className="text-white" />
                </div>
            </div>
        );
    }

    // Entrada (Verde)
    if (checkInRes) {
        return (
            <div 
                className="absolute inset-0 bg-emerald-500 cursor-pointer group flex items-center justify-center overflow-hidden"
                onClick={() => handleDayClick(roomId, day)}
            >
                <span className="text-[8px] font-black text-white uppercase truncate px-1">IN</span>
                <div className="hidden group-hover:flex absolute inset-0 bg-black/10 items-center justify-center">
                    <Edit size={14} className="text-white" />
                </div>
            </div>
        );
    }

    // Salida (Rojo)
    if (checkOutRes) {
        return (
            <div 
                className="absolute inset-0 bg-rose-500 cursor-pointer group flex items-center justify-center overflow-hidden"
                onClick={() => handleDayClick(roomId, day)}
            >
                <span className="text-[8px] font-black text-white uppercase truncate px-1">OUT</span>
                <div className="hidden group-hover:flex absolute inset-0 bg-black/10 items-center justify-center">
                    <Edit size={14} className="text-white" />
                </div>
            </div>
        );
    }

    // Estancia (Verde claro o mismo verde de entrada si prefiere)
    if (stayRes) {
        return (
            <div 
                className="absolute inset-0 bg-emerald-100 cursor-pointer group border-x border-emerald-200/50"
                onClick={() => handleDayClick(roomId, day)}
            >
                <div className="hidden group-hover:flex absolute inset-0 bg-emerald-200/50 items-center justify-center">
                    <Edit size={14} className="text-indigo-600" />
                </div>
            </div>
        );
    }

    return null;
  };

  const handleDayClick = (roomId: string, day: number) => {
      const { checkInRes, checkOutRes, stayRes } = getCellDetails(roomId, day);
      const res = checkInRes || checkOutRes || stayRes;
      if (res) {
          setEditingResId(res.id);
          setShowModal(true);
      }
  };

  const resetForm = () => {
      setEditingResId(null);
      setShowModal(true);
  };

  return (
    <div className="h-[calc(100vh-2rem)] flex flex-col space-y-4">
      <div className="flex justify-between items-center">
        <h2 className="text-3xl font-black text-slate-900">Calendario</h2>

        <div className="flex items-center gap-4">
            <button 
                onClick={resetForm}
                className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl flex items-center hover:bg-indigo-700 transition shadow-lg shadow-indigo-100 font-bold"
            >
                <Plus size={18} className="mr-2" /> Nueva Reserva
            </button>

            <div className="flex items-center space-x-4 bg-white p-2 rounded-2xl border border-slate-200 shadow-sm">
                <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-slate-100 rounded-full text-slate-600 transition-colors"><ChevronLeft size={20} /></button>
                <span className="text-sm font-black uppercase min-w-[140px] text-center text-slate-800 tracking-widest">{monthName}</span>
                <button onClick={() => changeMonth(1)} className="p-2 hover:bg-slate-100 rounded-full text-slate-600 transition-colors"><ChevronRight size={20} /></button>
            </div>
        </div>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-auto flex-1 custom-scrollbar">
        <table className="w-full border-collapse table-fixed">
          <thead className="bg-slate-50 sticky top-0 z-10">
            <tr>
              <th className="p-3 border-b border-r border-slate-200 w-32 min-w-[128px] text-left text-[10px] font-black uppercase text-slate-500 bg-slate-50 sticky left-0 z-20">
                Departamento
              </th>
              {daysArray.map(day => (
                <th key={day} className="p-2 border-b border-slate-200 w-8 min-w-[32px] text-center text-[10px] text-slate-400 font-black">
                  {day}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {rooms.map(room => (
              <tr key={room.id} className="hover:bg-slate-50/50">
                <td className="p-3 border-b border-r border-slate-200 font-black text-slate-700 sticky left-0 bg-white z-10 text-xs">
                  {room.number}
                  <span className="block text-[9px] text-slate-400 font-bold uppercase tracking-tighter">{room.type.split(' ')[0]}</span>
                </td>
                {daysArray.map(day => (
                    <td 
                      key={day} 
                      className="border-b border-r border-slate-100 h-12 relative transition-all"
                    >
                       {renderCellContent(room.id, day)}
                    </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="flex gap-6 text-[10px] font-black uppercase text-slate-400 tracking-widest px-2">
        <div className="flex items-center"><span className="w-3 h-3 bg-white border-2 border-slate-200 rounded-sm mr-2"></span> Libre</div>
        <div className="flex items-center"><span className="w-3 h-3 bg-emerald-500 rounded-sm mr-2"></span> Entrada</div>
        <div className="flex items-center"><span className="w-3 h-3 bg-rose-500 rounded-sm mr-2"></span> Salida</div>
        <div className="flex items-center"><span className="w-3 h-3 rounded-sm mr-2" style={{ background: 'linear-gradient(135deg, #f43f5e 50%, #10b981 50%)' }}></span> Rotación</div>
        <div className="flex items-center"><span className="w-3 h-3 bg-emerald-100 rounded-sm mr-2"></span> Estancia</div>
      </div>

      <ReservationModal isOpen={showModal} onClose={() => { setShowModal(false); setEditingResId(null); }} editingResId={editingResId} />
    </div>
  );
};

