import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { ShoppingBag, Wrench, Plus, Minus, AlertTriangle, Trash2, Edit, X, Brush } from 'lucide-react';
import { Product, MaintenanceItem } from '../types';

const Stock: React.FC = () => {
  const { products, maintenanceItems, updateProductStock, updateMaintenanceStock, addProduct, updateProduct, deleteProduct, addMaintenanceItem, updateMaintenanceItem, deleteMaintenanceItem, currentUser } = useApp();

  const isAdmin = currentUser?.role === 'admin';
  const [activeTab, setActiveTab] = useState<'sales' | 'maintenance'>(isAdmin ? 'sales' : 'maintenance');

  const [showModal, setShowModal] = useState(false);
  const [editingItem, setEditingItem] = useState<Product | MaintenanceItem | null>(null);
  const [newProduct, setNewProduct] = useState<Partial<Product>>({ name: '', category: '', price: 0, stock: 0 });
  const [newItem, setNewItem] = useState<Partial<MaintenanceItem>>({ name: '', category: '', unit: '', stock: 0, minStock: 0 });

  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [itemToDelete, setItemToDelete] = useState<{id: string, type: 'product' | 'maintenance'} | null>(null);

  const handleOpenEdit = (item: Product | MaintenanceItem) => {
      if (!isAdmin) return;
      setEditingItem(item);
      if (activeTab === 'sales') {
          setNewProduct(item as Product);
      } else {
          setNewItem(item as MaintenanceItem);
      }
      setShowModal(true);
  };

  const handleSave = () => {
      if (!isAdmin) return;
      if (activeTab === 'sales') {
          if(!newProduct.name) return;
          if (editingItem) {
              updateProduct({ ...editingItem, ...newProduct } as Product);
          } else {
              addProduct({ ...newProduct, id: `p-${Date.now()}` } as Product);
          }
      } else {
          if(!newItem.name) return;
          if (editingItem) {
              updateMaintenanceItem({ ...editingItem, ...newItem } as MaintenanceItem);
          } else {
              addMaintenanceItem({ ...newItem, id: `m-${Date.now()}` } as MaintenanceItem);
          }
      }
      setShowModal(false);
      setEditingItem(null);
      setNewProduct({ name: '', category: '', price: 0, stock: 0 });
      setNewItem({ name: '', category: '', unit: '', stock: 0, minStock: 0 });
  };

  const requestDelete = (e: React.MouseEvent, id: string, type: 'product' | 'maintenance') => {
      e.stopPropagation();
      if (!isAdmin) return;
      setItemToDelete({ id, type });
      setShowDeleteModal(true);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">
                {isAdmin ? 'Control de Stock' : 'Stock de Limpieza'}
            </h2>
            <p className="text-slate-500 font-bold text-xs uppercase tracking-widest mt-1">
                {isAdmin ? 'Gestión total de inventario y consumibles' : 'Registro de uso de insumos por limpieza'}
            </p>
        </div>
        {isAdmin && (
            <button 
                onClick={() => { setEditingItem(null); setShowModal(true); }}
                className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl flex items-center hover:bg-indigo-700 transition shadow-lg shadow-indigo-100 font-bold"
            >
                <Plus size={18} className="mr-2" />
                NUEVO ITEM
            </button>
        )}
      </div>

      <div className="flex gap-4 border-b-2 border-slate-100">
        {isAdmin && (
            <button onClick={() => setActiveTab('sales')} className={`pb-4 px-2 flex items-center font-black text-xs uppercase tracking-widest transition-all ${activeTab === 'sales' ? 'border-b-4 border-indigo-600 text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}>
                <ShoppingBag size={16} className="mr-2" /> TIENDA
            </button>
        )}
        <button onClick={() => setActiveTab('maintenance')} className={`pb-4 px-2 flex items-center font-black text-xs uppercase tracking-widest transition-all ${activeTab === 'maintenance' ? 'border-b-4 border-indigo-600 text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}>
          <Brush size={16} className="mr-2" /> INSUMOS LIMPIEZA
        </button>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase font-black tracking-widest border-b border-slate-100">
              <th className="p-5">Detalle</th>
              <th className="p-5">Categoría</th>
              <th className="p-5 text-center">Stock Actual</th>
              <th className="p-5 text-right">Registro de Uso</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {activeTab === 'sales' && isAdmin ? (
              products.map(product => (
                <tr key={product.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="p-5">
                    <div className="font-black text-slate-900">{product.name}</div>
                    <div className="text-[10px] text-indigo-600 font-black tracking-widest uppercase">${product.price.toFixed(2)}</div>
                  </td>
                  <td className="p-5 text-xs font-bold text-slate-500 uppercase">{product.category}</td>
                  <td className="p-5 text-center">
                    <span className={`px-4 py-1 rounded-lg text-xs font-black ${product.stock <= 5 ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {product.stock}
                    </span>
                  </td>
                  <td className="p-5 text-right">
                    <div className="flex justify-end items-center gap-2">
                        <button onClick={() => updateProductStock(product.id, -1)} className="p-2 border-2 border-slate-100 rounded-xl hover:bg-slate-100 text-slate-400"><Minus size={14}/></button>
                        <button onClick={() => updateProductStock(product.id, 1)} className="p-2 bg-indigo-50 border-2 border-indigo-100 rounded-xl hover:bg-indigo-100 text-indigo-600"><Plus size={14}/></button>

                        <button onClick={() => handleOpenEdit(product)} className="p-2 bg-slate-50 text-slate-400 hover:text-indigo-600 rounded-xl transition-colors ml-4"><Edit size={16}/></button>
                        <button onClick={(e) => requestDelete(e, product.id, 'product')} className="p-2 text-rose-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl transition-colors"><Trash2 size={16}/></button>
                    </div>
                  </td>
                </tr>
              ))
            ) : (
              maintenanceItems.map(item => (
                <tr key={item.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="p-5">
                    <div className="font-black text-slate-900">{item.name}</div>
                    <div className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.unit}</div>
                  </td>
                  <td className="p-5 text-xs font-bold text-slate-500 uppercase">{item.category}</td>
                  <td className="p-5 text-center">
                    <span className={`px-4 py-1 rounded-lg text-xs font-black ${item.stock <= item.minStock ? 'bg-amber-100 text-amber-700' : 'bg-blue-100 text-blue-700'}`}>
                        {item.stock}
                    </span>
                  </td>
                  <td className="p-5 text-right">
                    <div className="flex justify-end items-center gap-2">
                        <button 
                            onClick={() => updateMaintenanceStock(item.id, -1)} 
                            className="p-4 bg-rose-50 border-2 border-rose-100 rounded-2xl hover:bg-rose-100 text-rose-600 flex items-center font-black text-xs gap-2 transition-all active:scale-95"
                            title="Descontar 1 unidad por uso"
                        >
                            <Minus size={16}/> MARCAR USO
                        </button>

                        {isAdmin && (
                            <div className="flex gap-2 ml-4">
                                <button onClick={() => updateMaintenanceStock(item.id, 1)} className="p-2 bg-indigo-50 border-2 border-indigo-100 rounded-xl hover:bg-indigo-100 text-indigo-600"><Plus size={14}/></button>
                                <button onClick={() => handleOpenEdit(item)} className="p-2 bg-slate-50 text-slate-400 hover:text-indigo-600 rounded-xl transition-colors"><Edit size={16}/></button>
                                <button onClick={(e) => requestDelete(e, item.id, 'maintenance')} className="p-2 text-rose-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl transition-colors"><Trash2 size={16}/></button>
                            </div>
                        )}
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
        {activeTab === 'maintenance' && maintenanceItems.length === 0 && (
            <div className="p-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Sin insumos registrados</div>
        )}
      </div>

      {showModal && isAdmin && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[200] p-4">
            <div className="bg-white p-8 rounded-3xl w-full max-w-md shadow-2xl animate-in zoom-in duration-200">
                <div className="flex justify-between items-center mb-8">
                    <h3 className="text-2xl font-black text-slate-900">
                        {editingItem ? 'Editar Item' : 'Nuevo Item'}
                    </h3>
                    <button onClick={() => setShowModal(false)} className="bg-slate-100 p-2 rounded-full text-slate-400 hover:text-slate-900 transition-colors"><X size={24}/></button>
                </div>

                <div className="space-y-5">
                    <div>
                        <label className="block text-[10px] font-black uppercase text-slate-500 mb-2 ml-1">Nombre</label>
                        <input type="text" className="w-full border-2 border-slate-100 rounded-2xl p-4 font-black text-slate-900 outline-none focus:border-indigo-500" value={activeTab === 'sales' ? newProduct.name : newItem.name} onChange={e => activeTab === 'sales' ? setNewProduct({...newProduct, name: e.target.value}) : setNewItem({...newItem, name: e.target.value})} />
                    </div>
                    <div>
                        <label className="block text-[10px] font-black uppercase text-slate-500 mb-2 ml-1">Categoría</label>
                        <input type="text" className="w-full border-2 border-slate-100 rounded-2xl p-4 font-black text-slate-900 outline-none focus:border-indigo-500" value={activeTab === 'sales' ? newProduct.category : newItem.category} onChange={e => activeTab === 'sales' ? setNewProduct({...newProduct, category: e.target.value}) : setNewItem({...newItem, category: e.target.value})} />
                    </div>
                    {activeTab === 'sales' ? (
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-[10px] font-black uppercase text-slate-500 mb-2 ml-1">Precio ($)</label>
                                <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 font-black text-slate-900 outline-none focus:border-indigo-500" value={newProduct.price} onChange={e => setNewProduct({...newProduct, price: parseFloat(e.target.value)})} />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black uppercase text-slate-500 mb-2 ml-1">Stock Inicial</label>
                                <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 font-black text-slate-900 outline-none focus:border-indigo-500" value={newProduct.stock} onChange={e => setNewProduct({...newProduct, stock: parseInt(e.target.value)})} />
                            </div>
                        </div>
                    ) : (
                        <div className="grid grid-cols-3 gap-4">
                            <div>
                                <label className="block text-[10px] font-black uppercase text-slate-500 mb-2 ml-1">Unidad</label>
                                <input type="text" className="w-full border-2 border-slate-100 rounded-2xl p-4 font-black text-slate-900 outline-none focus:border-indigo-500" value={newItem.unit} onChange={e => setNewItem({...newItem, unit: e.target.value})} />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black uppercase text-slate-500 mb-2 ml-1">Stock</label>
                                <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 font-black text-slate-900 outline-none focus:border-indigo-500" value={newItem.stock} onChange={e => setNewItem({...newItem, stock: parseInt(e.target.value)})} />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black uppercase text-slate-500 mb-2 ml-1">Min. Alerta</label>
                                <input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 font-black text-slate-900 outline-none focus:border-indigo-500" value={newItem.minStock} onChange={e => setNewItem({...newItem, minStock: parseInt(e.target.value)})} />
                            </div>
                        </div>
                    )}
                </div>

                <div className="mt-10 flex gap-4">
                    <button onClick={() => setShowModal(false)} className="flex-1 py-4 text-slate-400 font-black hover:bg-slate-100 rounded-2xl transition-colors uppercase text-xs">Cancelar</button>
                    <button onClick={handleSave} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black shadow-lg uppercase text-xs">Guardar Item</button>
                </div>
            </div>
        </div>
      )}

      {showDeleteModal && isAdmin && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[210] p-4">
            <div className="bg-white p-10 rounded-3xl w-full max-w-sm shadow-2xl text-center border border-slate-200">
                <AlertTriangle size={40} className="mx-auto text-rose-600 mb-6" />
                <h3 className="text-2xl font-black text-slate-900 mb-2 text-center w-full">¿Eliminar definitivamente?</h3>
                <div className="flex gap-4 mt-8">
                    <button onClick={() => setShowDeleteModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-700 rounded-2xl font-black">NO</button>
                    <button onClick={() => { 
                        if (itemToDelete?.type === 'product') deleteProduct(itemToDelete.id);
                        else deleteMaintenanceItem(itemToDelete!.id);
                        setShowDeleteModal(false); 
                    }} className="flex-1 py-4 bg-rose-600 text-white rounded-2xl font-black shadow-lg">SÍ, BORRAR</button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default Stock;

