  const [newItem, setNewItem] = useState<Partial<MaintenanceItem>>({ name: '', category: '', unit: '', stock: 0, minStock: 0 });

  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [itemToDelete, setItemToDelete] = useState<{id: string, type: 'product' | 'maintenance'} | null>(null);

  const handleOpenEdit = (item: Product | MaintenanceItem) => {
      if (!isAdmin) return;
      setEditingItem(item);
      if (activeTab === 'sales') {
          setNewProduct(item as Product);
      } else {
          setNewItem(item as MaintenanceItem);
      }
      setShowModal(true);
  };

  const handleSave = () => {
      if (!isAdmin) return;
      if (activeTab === 'sales') {
          if(!newProduct.name) return;
          if (editingItem) {
