          } else {
              addMaintenanceItem({ ...newItem, id: `m-${Date.now()}` } as MaintenanceItem);
          }
      }
      setShowModal(false);
      setEditingItem(null);
      setNewProduct({ name: '', category: '', price: 0, stock: 0 });
      setNewItem({ name: '', category: '', unit: '', stock: 0, minStock: 0 });
