        <p className="text-3xl font-black text-slate-900">{count}</p>
      </div>
    </div>
  );

  const handleUpdateTime = (resId: string, type: 'in' | 'out', time: string) => {
      const res = reservations.find(r => r.id === resId);
      if (res) {
          updateReservation({
              ...res,
              [type === 'in' ? 'checkInTime' : 'checkOutTime']: time
          });
      }
  };

  return (
