                                        className="w-full border-2 border-slate-100 rounded-2xl p-4 pl-12 bg-slate-50/50 text-slate-900 font-black outline-none focus:border-indigo-500" 
                                        placeholder="1"
                                        value={numPeople === 0 ? '' : numPeople}
